export interface Interface {
  readonly getOrCompute: <R = never>(
    key: CacheKey,
    compute: () => Effect.Effect<Tool.ExecuteResult, never, R>,
  ) => Effect.Effect<Tool.ExecuteResult, never, R>
  readonly invalidate: () => Effect.Effect<void>
}

